// nlp-and-conversational-ai-development-services

import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
import Layout_v2 from "@components/layout_v2";
import Seo from "@components/seo";
import { useLocation } from "@reach/router";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";
import NLPandConversationalAIDevelopmentServicesPage from "@screens/ai-screens/nlp-and-conversational-ai-development-services";

const NLPandConversationalAIDevelopmentServiceCompany = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "NLP and Conversational AI Development Service", link: null },
  ];
  const { data } = props;
  const location = useLocation();
  const fileUrl =
    data?.hire3dDesignerImg?.childImageSharp?.gatsbyImageData?.images?.fallback
      ?.src;
  const validData = data?.allMetaJson?.nodes[0];
  const validFaq = data?.allFaqJson?.nodes[0]?.faqs;
  // console.log("validFaq", validFaq);
  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <main>
        <NLPandConversationalAIDevelopmentServicesPage db={db} faq={validFaq} />
      </main>
    </Layout_v2>
  );
};

export default NLPandConversationalAIDevelopmentServiceCompany;
export const queryData = graphql`
  query MyQuery {
    hire3dDesignerImg: file(
      relativePath: { eq: "nlp-and-conversational-ai-development-services.png" }
    ) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(
      filter: { slug: { eq: "nlp-and-conversational-ai-development-services" } }
    ) {
      nodes {
        metaTitle
        title
        slug
        description
      }
    }
    allFaqJson(
      filter: { slug: { eq: "nlp-and-conversational-ai-development-services" } }
    ) {
      nodes {
        slug
        faqs {
          question
          answer
          status
        }
      }
    }
  }
`;
